/**
 * Factor types that can appear in an `mfa_required` error's `mfa_requirements` payload.
 */
export type MfaRequiredFactorType =
  | 'otp'
  | 'oob'
  | 'email'
  | 'webauthn-roaming'
  | 'webauthn-platform'
  | 'push-notification'
  | 'phone';

/**
 * Describes which MFA factors the user must challenge or enroll.
 */
export interface MfaRequirements {
  challenge?: Array<{ type: MfaRequiredFactorType }>;
  enroll?: Array<{ type: MfaRequiredFactorType }>;
}

/**
 * Interface to represent an OAuth2 error.
 * When the error is `mfa_required`, `mfa_token` and `mfa_requirements` will be populated.
 */
export interface OAuth2Error {
  error: string;
  error_description: string;
  message?: string;
  mfa_token?: string;
  mfa_requirements?: MfaRequirements;
}

/**
 * Normalizes an unknown error (typically thrown by `openid-client`) into an
 * {@link OAuth2Error}.
 *
 * On an `mfa_required` response, `openid-client` nests the server's `mfa_token`
 * and `mfa_requirements` under `error.cause`; this lifts them to the top level
 * so {@link isMfaRequiredError} can detect the error and callers can continue
 * with the MFA APIs.
 *
 * @internal
 */
export function toOAuth2Error(e: unknown): OAuth2Error {
  if (typeof e !== 'object' || e === null) {
    return { error: 'unknown_error', error_description: String(e) };
  }
  const err = e as { error?: string; error_description?: string; cause?: Record<string, unknown>; message?: string };
  const base: OAuth2Error = {
    error: err.error ?? '',
    error_description: err.error_description ?? '',
    message: err.message,
  };
  if (err.error === 'mfa_required' && err.cause) {
    base.mfa_token = typeof err.cause.mfa_token === 'string' ? err.cause.mfa_token : undefined;
    const req = err.cause.mfa_requirements;
    if (typeof req === 'object' && req !== null) {
      base.mfa_requirements = req as OAuth2Error['mfa_requirements'];
    }
  }
  return base;
}

/**
 * Error codes used for {@link NotSupportedError}
 */
export enum NotSupportedErrorCode {
  PAR_NOT_SUPPORTED = 'par_not_supported_error',
  MTLS_WITHOUT_CUSTOMFETCH_NOT_SUPPORT = 'mtls_without_custom_fetch_not_supported',
}

/**
 * Error thrown when a feature is not supported.
 * For example, when trying to use Pushed Authorization Requests (PAR) but the Auth0 tenant was not configured to support it.
 */
export class NotSupportedError extends Error {
  public code: string;

  constructor(code: string, message: string) {
    super(message);
    this.name = 'NotSupportedError';
    this.code = code;
  }
}

/**
 * Base class for API errors, containing the error, error_description and message (if available).
 */
abstract class ApiError extends Error {
  public cause?: OAuth2Error;
  public code: string;

  constructor(code: string, message: string, cause?: OAuth2Error) {
    super(message);

    this.code = code;
    this.cause = cause && {
      error: cause.error,
      error_description: cause.error_description,
      message: cause.message,
      mfa_token: cause.mfa_token,
      mfa_requirements: cause.mfa_requirements,
    };
  }
}

/**
 * Error thrown when trying to get an access token.
 */
export class TokenByCodeError extends ApiError {
  constructor(message: string, cause?: OAuth2Error) {
    super('token_by_code_error', message, cause);
    this.name = 'TokenByCodeError';
  }
}

